    val linearEquations = a("math-linear-equation-balance","Equation Balance","math-linear-equations",setOf(CLASS_7,CLASS_8,CLASS_9,CLASS_10),"Connect identical operations on both sides of an equation to its solution.","ax + b = c, so x = (c - b) / a",
