        listOf(ActivityPreset("simple","2x + 4 = 12",mapOf("a" to 2.0,"b" to 4.0,"c" to 12.0)),ActivityPreset("negative","3x - 6 = 9",mapOf("a" to 3.0,"b" to -6.0,"c" to 9.0))),
