    val triangles = a("math-triangle-lab","Triangle Invariant Lab","math-triangles",setOf(CLASS_7,CLASS_9,CLASS_10),"Manipulate a triangle and verify its angle and area relationships.","Area = 1/2 × base × height; interior angles sum to 180°",
        listOf(c("base","Base",2.0,14.0,.5,8.0,"cm"),c("height","Height",1.0,10.0,.5,5.0,"cm"),c("offset","Apex offset",0.0,14.0,.5,4.0,"cm")),
        listOf(ActivityPreset("right","Right triangle",mapOf("base" to 8.0,"height" to 6.0,"offset" to 0.0)),ActivityPreset("isosceles","Isosceles",mapOf("base" to 8.0,"height" to 5.0,"offset" to 4.0))),
        listOf(DiagramPart("a","vertex A","left base vertex"),DiagramPart("b","vertex B","right base vertex"),DiagramPart("c","vertex C","draggable apex"),DiagramPart("altitude","altitude","perpendicular height")),
        { q->val b=q.getValue("base");val h=q.getValue("height");val o=q.getValue("offset");val s1=hypot(o,h);val s2=hypot(b-o,h);val a1=Math.toDegrees(atan2(h,o.coerceAtLeast(1e-9)));val a2=Math.toDegrees(atan2(h,(b-o).coerceAtLeast(1e-9)));val a3=180-a1-a2;state(q+mapOf("area" to b*h/2,"angleSum" to a1+a2+a3),mapOf("base" to "cm","height" to "cm","offset" to "cm","area" to "cm²","angleSum" to "°"),mapOf("sides" to "${"%.1f".format(s1)}, ${"%.1f".format(s2)}, $b cm","angles" to "${"%.1f".format(a1)}° + ${"%.1f".format(a2)}° + ${"%.1f".format(a3)}° = 180°"),listOf(PlotPoint(0.0,0.0),PlotPoint(b,0.0),PlotPoint(o,h),PlotPoint(0.0,0.0)),listOf("Drag the apex.","Compare base × height with the enclosing parallelogram."),"The apex can slide parallel to the base: height and area stay fixed; the angle sum remains 180°.","c") },
