    val coordinateGeometry = a("math-coordinate-geometry","Coordinate Geometry Explorer","math-coordinate-geometry",setOf(CLASS_9,CLASS_10,CLASS_11),"Relate two plotted points to slope, distance, and midpoint.","m = Δy/Δx; d = √(Δx²+Δy²); midpoint = ((x₁+x₂)/2,(y₁+y₂)/2)",
