        listOf(ActivityPreset("rise-run","Rise 4, run 6",mapOf("x1" to -2.0,"y1" to 1.0,"x2" to 4.0,"y2" to 5.0)),ActivityPreset("negative","Negative slope",mapOf("x1" to -4.0,"y1" to 5.0,"x2" to 4.0,"y2" to -3.0))),
        listOf(DiagramPart("p1","point one","first endpoint"),DiagramPart("p2","point two","second endpoint"),DiagramPart("slope-triangle","slope triangle","run and rise")),
        {q->val dx=q.getValue("x2")-q.getValue("x1");val dy=q.getValue("y2")-q.getValue("y1");val slope=if(abs(dx)<1e-9) Double.NaN else dy/dx;val d=hypot(dx,dy);state(q+mapOf("slope" to slope,"distance" to d,"midX" to (q.getValue("x1")+q.getValue("x2"))/2,"midY" to (q.getValue("y1")+q.getValue("y2"))/2),mapOf("x1" to "units","y1" to "units","x2" to "units","y2" to "units","slope" to "","distance" to "units","midX" to "units","midY" to "units"),mapOf("delta" to "rise $dy, run $dx","slope" to if(slope.isNaN()) "vertical: undefined slope" else "slope ${"%.2f".format(slope)}"),listOf(PlotPoint(q.getValue("x1"),q.getValue("y1")),PlotPoint(q.getValue("x2"),q.getValue("y2"))),listOf("Plot both endpoints.","Draw the horizontal run and vertical rise."),"Distance is the hypotenuse of the slope triangle; the midpoint averages corresponding coordinates.","slope-triangle")},
