        listOf(DiagramPart("opposite","opposite side","side across from theta"),DiagramPart("adjacent","adjacent side","non-hypotenuse side beside theta"),DiagramPart("hypotenuse","hypotenuse","side opposite right angle")),
        {q->val rad=Math.toRadians(q.getValue("angle"));val h=q.getValue("hypotenuse");val op=h*sin(rad);val ad=h*cos(rad);state(q+mapOf("opposite" to op,"adjacent" to ad,"sin" to sin(rad),"cos" to cos(rad),"tan" to tan(rad)),mapOf("angle" to "°","hypotenuse" to "cm","opposite" to "cm","adjacent" to "cm","sin" to "","cos" to "","tan" to ""),mapOf("lengths" to "opposite ${"%.2f".format(op)} cm, adjacent ${"%.2f".format(ad)} cm","ratios" to "sin ${"%.3f".format(sin(rad))}, cos ${"%.3f".format(cos(rad))}, tan ${"%.3f".format(tan(rad))}"),listOf(PlotPoint(0.0,0.0),PlotPoint(ad,0.0),PlotPoint(ad,op),PlotPoint(0.0,0.0)),listOf("Choose an angle.","Scale the triangle without changing the angle."),"Scaling changes all lengths by the same factor, so each side ratio is invariant.","hypotenuse")},
        listOf(challenge("sinhalf","sin θ = 0.5","Find an angle with sine one half."){near(it.values["sin"],.5,.01)},challenge("equallegs","Equal legs","Make opposite equal adjacent."){near(it.values["opposite"],it.values["adjacent"]?:0.0,.01)},challenge("tanroot3","tan θ ≈ √3","Find the angle whose tangent is √3."){near(it.values["tan"],sqrt(3.0),.04)}))

    val probability = a("math-probability-experiment","Probability Experiment","math-probability",setOf(CLASS_9,CLASS_10,CLASS_11,CLASS_12),"Compare theoretical probability with a reproducible experimental frequency.","P(E) = favourable outcomes / total outcomes; expected frequency = nP(E)",
        listOf(c("favourable","Favourable outcomes",1.0,10.0,1.0,1.0,"outcomes"),c("total","Total outcomes",2.0,12.0,1.0,6.0,"outcomes"),c("trials","Trials",10.0,1000.0,10.0,100.0,"trials")),
        listOf(ActivityPreset("die","One face on a die",mapOf("favourable" to 1.0,"total" to 6.0,"trials" to 120.0)),ActivityPreset("coin","Heads",mapOf("favourable" to 1.0,"total" to 2.0,"trials" to 100.0))),
        listOf(DiagramPart("sample-space","sample space","equally likely outcome cells"),DiagramPart("frequency-bar","frequency bar","expected and deterministic observed proportions")),
        {q->val total=q.getValue("total");val fav=q.getValue("favourable").coerceAtMost(total);val n=q.getValue("trials");val p=fav/total;val observed=((n*p + sin(n+fav)*sqrt(n*p*(1-p).coerceAtLeast(0.0))).roundToInt()).coerceIn(0,n.toInt());state(q+mapOf("favourableUsed" to fav,"probability" to p,"expected" to n*p,"observed" to observed.toDouble(),"observedProbability" to observed/n),mapOf("favourable" to "outcomes","total" to "outcomes","trials" to "trials","favourableUsed" to "outcomes","probability" to "","expected" to "successes","observed" to "successes","observedProbability" to ""),mapOf("theory" to "P(E) = ${"%.3f".format(p)}","experiment" to "$observed successes in ${n.toInt()} trials"),listOf(PlotPoint(0.0,p,"theory"),PlotPoint(1.0,observed/n,"experiment")),listOf("Build the sample space.","Predict a count, then run the reproducible trial model."),"Larger trial counts tend to bring relative frequency closer to theoretical probability, without guaranteeing an exact count.","frequency-bar")},
        listOf(challenge("half","Probability 1/2","Build an event with probability one half."){near(it.values["probability"],.5,.001)},challenge("quarter","Probability 1/4","Build an event with probability one quarter."){near(it.values["probability"],.25,.001)},challenge("expected100","Expected count 100","Make expected successes 100."){near(it.values["expected"],100.0,.01)}))

    val definitions = listOf(linearEquations,triangles,coordinateGeometry,trigonometry,probability)
